/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 *
 * DECISION CHANGE (Session 9): The original model assumed email-only notifications.
 * With SMS support added in Session 8 and webhook adapters already present, this
 * model now supports per-channel preferences for email, SMS, and webhook.
 * The email-only assumption from Session 3 is explicitly invalidated.
 *
 * Backward compatibility: Existing code that only sets `email` preferences will
 * continue to work — SMS and webhook default to disabled so existing users are
 * not opted into new channels without explicit action.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification settings.
 */
export interface SmsPreferences {
  enabled: boolean;
  phoneNumber: string;
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification settings.
 */
export interface WebhookPreferences {
  enabled: boolean;
  url: string;
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 * All channel settings are optional and will be merged with defaults.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * All notification categories that users can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'account-update',
  'system-alert',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default SMS preferences for new users.
 * Disabled by default — users must explicitly opt in and provide a phone number.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  phoneNumber: '',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Default webhook preferences for new users.
 * Disabled by default — users must explicitly opt in and provide a URL.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  url: '',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences, SmsPreferences, WebhookPreferences } from '../models/user-preferences.js';
import { DEFAULT_SMS_PREFERENCES, DEFAULT_WEBHOOK_PREFERENCES } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailPreferences,
      sms: record['sms'] ? JSON.parse(record['sms'] as string) as SmsPreferences : { ...DEFAULT_SMS_PREFERENCES },
      webhook: record['webhook'] ? JSON.parse(record['webhook'] as string) as WebhookPreferences : { ...DEFAULT_WEBHOOK_PREFERENCES },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification preferences and
 * methods to check whether a notification should be sent on each
 * channel based on the user's current settings.
 *
 * Supports email, SMS, and webhook channels with per-channel
 * enabled/disabled state and category subscriptions.
 *
 * Depends on:
 * - PreferencesRepository for persistence
 * - UserRepository to verify users exist
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import {
  validatePreferencesUserExists,
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepo: PreferencesRepository,
    private userRepo: UserRepository,
  ) {}

  /**
   * Create notification preferences for a user.
   * Merges provided settings with defaults for each channel.
   */
  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
    const user = this.userRepo.findById(input.userId);
    validatePreferencesUserExists(user, input.userId);

    const existing = this.preferencesRepo.findByUserId(input.userId);
    validatePreferencesNotExist(existing, input.userId);

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: {
        ...DEFAULT_EMAIL_PREFERENCES,
        ...input.email,
        subscribedCategories: input.email?.subscribedCategories
          ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
      },
      sms: {
        ...DEFAULT_SMS_PREFERENCES,
        ...input.sms,
        subscribedCategories: input.sms?.subscribedCategories
          ?? [...DEFAULT_SMS_PREFERENCES.subscribedCategories],
      },
      webhook: {
        ...DEFAULT_WEBHOOK_PREFERENCES,
        ...input.webhook,
        subscribedCategories: input.webhook?.subscribedCategories
          ?? [...DEFAULT_WEBHOOK_PREFERENCES.subscribedCategories],
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepo.save(preferences);
    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);
    return preferences;
  }

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepo.findByUserId(userId);
  }

  /**
   * Update a user's notification preferences.
   */
  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
    const existing = this.preferencesRepo.findByUserId(userId);
    validatePreferencesExist(existing, userId);

    const updatedEmail = input.email
      ? {
          ...existing.email,
          ...input.email,
          subscribedCategories: input.email.subscribedCategories
            ?? existing.email.subscribedCategories,
        }
      : existing.email;

    const updatedSms = input.sms
      ? {
          ...existing.sms,
          ...input.sms,
          subscribedCategories: input.sms.subscribedCategories
            ?? existing.sms.subscribedCategories,
        }
      : existing.sms;

    const updatedWebhook = input.webhook
      ? {
          ...existing.webhook,
          ...input.webhook,
          subscribedCategories: input.webhook.subscribedCategories
            ?? existing.webhook.subscribedCategories,
        }
      : existing.webhook;

    const updated = this.preferencesRepo.update(existing.id, {
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    } as Partial<UserPreferences>);

    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Delete a user's preferences.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.preferencesRepo.findByUserId(userId);
    if (!existing) {
      return false;
    }
    return this.preferencesRepo.delete(existing.id);
  }

  /**
   * Check whether an email notification should be sent to a user
   * based on their preferences.
   *
   * Returns true if:
   * - The user has no preferences (default: send all)
   * - Email is enabled AND the notification type is in their subscribed categories
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepo.findByUserId(userId);

    // No preferences means default behavior: send everything
    if (!prefs) {
      return true;
    }

    if (!prefs.email.enabled) {
      return false;
    }

    return prefs.email.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether an SMS notification should be sent to a user
   * based on their preferences.
   *
   * Returns false if:
   * - The user has no preferences (SMS is opt-in, not default)
   * - SMS is disabled
   * - No phone number is configured
   * - The notification type is not in their subscribed categories
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepo.findByUserId(userId);

    // No preferences means SMS is not configured (opt-in only)
    if (!prefs) {
      return false;
    }

    if (!prefs.sms.enabled) {
      return false;
    }

    if (!prefs.sms.phoneNumber || prefs.sms.phoneNumber.trim().length === 0) {
      return false;
    }

    return prefs.sms.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether a webhook notification should be sent to a user
   * based on their preferences.
   *
   * Returns false if:
   * - The user has no preferences (webhook is opt-in, not default)
   * - Webhook is disabled
   * - No URL is configured
   * - The notification type is not in their subscribed categories
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepo.findByUserId(userId);

    // No preferences means webhook is not configured (opt-in only)
    if (!prefs) {
      return false;
    }

    if (!prefs.webhook.enabled) {
      return false;
    }

    if (!prefs.webhook.url || prefs.webhook.url.trim().length === 0) {
      return false;
    }

    return prefs.webhook.subscribedCategories.includes(notificationType);
  }

  /**
   * Get the phone number for a user's SMS notifications.
   * Returns undefined if SMS is not configured.
   */
  getSmsPhoneNumber(userId: string): string | undefined {
    const prefs = this.preferencesRepo.findByUserId(userId);
    if (!prefs || !prefs.sms.phoneNumber) {
      return undefined;
    }
    return prefs.sms.phoneNumber;
  }

  /**
   * Get the webhook URL for a user's webhook notifications.
   * Returns undefined if webhook is not configured.
   */
  getWebhookUrl(userId: string): string | undefined {
    const prefs = this.preferencesRepo.findByUserId(userId);
    if (!prefs || !prefs.webhook.url) {
      return undefined;
    }
    return prefs.webhook.url;
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * NOTE: This service currently uses TWO different patterns for receiving
 * notifications, which is inconsistent and should be unified:
 *
 * 1. EventBus subscriptions (event-driven) — used for order:created events
 * 2. CallbackRegistry (direct callbacks) — used for order:status-changed events
 *
 * Both approaches work but the mixed usage makes the codebase harder to
 * maintain. A future refactor should pick ONE approach and use it consistently.
 *
 * Multi-channel support (Session 9): Event handlers now check per-channel
 * preferences and dispatch to email, SMS, and webhook channels independently.
 * Email remains the default for users with no preferences. SMS and webhook
 * are opt-in only.
 *
 * Depends on:
 * - EventBus (event system) for receiving some events
 * - CallbackRegistry (direct callbacks) for other events
 * - NotificationAdapter implementations for channel-specific delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter, NotificationResult } from '../adapters/notification.adapter.js';
import type { NotificationPayload, NotificationType } from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import type { NotificationHistoryService } from './notification-history.service.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  channel: string;
  status: 'sent' | 'failed';
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters = new Map<string, NotificationAdapter>();
  private preferencesService?: PreferencesService;
  private historyService?: NotificationHistoryService;

  constructor(private eventBus: EventBus, adapters?: NotificationAdapter[]) {
    if (adapters) {
      for (const adapter of adapters) {
        this.adapters.set(adapter.channel, adapter);
      }
    }
    this.registerHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   */
  setPreferencesService(preferencesService: PreferencesService): void {
    this.preferencesService = preferencesService;
  }

  /**
   * Set the history service for logging sent notifications.
   */
  setHistoryService(historyService: NotificationHistoryService): void {
    this.historyService = historyService;
  }

  /**
   * Register a notification adapter for a specific channel.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user on all opted-in channels.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    const userId = event.order.userId;
    const notificationType: NotificationType = 'order-confirmation';

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const subject = `Order Confirmation: ${event.order.id}`;
    const body = `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`;

    // Email: default channel, sends unless explicitly opted out
    if (!this.preferencesService || this.preferencesService.shouldSendEmail(userId, notificationType)) {
      this.logger.info(`Sending email order confirmation for order ${event.order.id}`);
      this.sendNotification({
        recipient: event.user.email,
        subject,
        body,
        type: notificationType,
        channel: 'email',
      });
    } else {
      this.logger.info(`Skipping email order confirmation for order ${event.order.id} — user opted out`);
    }

    // SMS: opt-in only, check preferences
    if (this.preferencesService?.shouldSendSms(userId, notificationType)) {
      const phoneNumber = this.preferencesService.getSmsPhoneNumber(userId);
      if (phoneNumber) {
        this.logger.info(`Sending SMS order confirmation for order ${event.order.id}`);
        this.sendNotification({
          recipient: phoneNumber,
          subject,
          body,
          type: notificationType,
          channel: 'sms',
          metadata: { phoneNumber },
        });
      }
    }

    // Webhook: opt-in only, check preferences
    if (this.preferencesService?.shouldSendWebhook(userId, notificationType)) {
      const webhookUrl = this.preferencesService.getWebhookUrl(userId);
      if (webhookUrl) {
        this.logger.info(`Sending webhook order confirmation for order ${event.order.id}`);
        this.sendNotification({
          recipient: event.user.email,
          subject,
          body,
          type: notificationType,
          channel: 'webhook',
          metadata: { webhookUrl },
        });
      }
    }
  }

  /**
   * Handle order status change — notify user of update on all opted-in channels.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const userId = event.order.userId;
    const notificationType: NotificationType = 'order-status-update';

    const subject = `Order Update: ${event.order.id}`;
    const body = `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`;

    // Email: default channel
    if (!this.preferencesService || this.preferencesService.shouldSendEmail(userId, notificationType)) {
      this.logger.info(
        `Sending email status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
      );
      this.sendNotification({
        recipient: userId,
        subject,
        body,
        type: notificationType,
        channel: 'email',
      });
    } else {
      this.logger.info(`Skipping email status update for order ${event.order.id} — user opted out`);
    }

    // SMS: opt-in only
    if (this.preferencesService?.shouldSendSms(userId, notificationType)) {
      const phoneNumber = this.preferencesService.getSmsPhoneNumber(userId);
      if (phoneNumber) {
        this.logger.info(`Sending SMS status update for order ${event.order.id}`);
        this.sendNotification({
          recipient: phoneNumber,
          subject,
          body,
          type: notificationType,
          channel: 'sms',
          metadata: { phoneNumber },
        });
      }
    }

    // Webhook: opt-in only
    if (this.preferencesService?.shouldSendWebhook(userId, notificationType)) {
      const webhookUrl = this.preferencesService.getWebhookUrl(userId);
      if (webhookUrl) {
        this.logger.info(`Sending webhook status update for order ${event.order.id}`);
        this.sendNotification({
          recipient: userId,
          subject,
          body,
          type: notificationType,
          channel: 'webhook',
          metadata: { webhookUrl },
        });
      }
    }
  }

  /**
   * Send a notification, dispatching to the appropriate adapter if available.
   */
  private sendNotification(payload: NotificationPayload): void {
    const adapter = this.adapters.get(payload.channel);

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      type: payload.type,
      channel: payload.channel,
      status: 'sent',
      sentAt: new Date(),
    };

    if (adapter) {
      adapter.send(payload).then((result: NotificationResult) => {
        if (!result.success) {
          notification.status = 'failed';
          this.logger.error(
            `Adapter failed for ${payload.channel}: ${result.error}`,
          );
        }
      });
    }

    this.notifications.push(notification);

    if (this.historyService) {
      this.historyService.log({
        recipient: notification.recipient,
        channel: payload.channel,
        type: payload.type,
        subject: notification.subject,
        body: notification.body,
        status: notification.status,
        timestamp: notification.sentAt,
        metadata: payload.metadata,
      });
    }

    this.logger.info(`Notification sent: ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import {
  ALL_NOTIFICATION_CATEGORIES,
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../../src/models/user-preferences.js';
import type { User } from '../../src/models/user.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;
  let testUser: User;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();

    testUser = {
      id: 'user-0001',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    userRepo.save(testUser);
  });

  describe('createPreferences', () => {
    it('should create preferences with defaults', () => {
      const prefs = service.createPreferences({ userId: 'user-0001' });

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with default SMS (disabled)', () => {
      const prefs = service.createPreferences({ userId: 'user-0001' });

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.phoneNumber).toBe('');
      expect(prefs.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with default webhook (disabled)', () => {
      const prefs = service.createPreferences({ userId: 'user-0001' });

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.url).toBe('');
      expect(prefs.webhook.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should create preferences with custom email settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: {
          enabled: true,
          frequency: 'daily-digest',
          subscribedCategories: ['order-confirmation', 'system-alert'],
        },
      });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.subscribedCategories).toEqual(['order-confirmation', 'system-alert']);
    });

    it('should create preferences with custom SMS settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        sms: {
          enabled: true,
          phoneNumber: '+1555123456',
          subscribedCategories: ['order-confirmation'],
        },
      });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.phoneNumber).toBe('+1555123456');
      expect(prefs.sms.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should create preferences with custom webhook settings', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        webhook: {
          enabled: true,
          url: 'https://hooks.example.com/notify',
          subscribedCategories: ['system-alert'],
        },
      });

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.url).toBe('https://hooks.example.com/notify');
      expect(prefs.webhook.subscribedCategories).toEqual(['system-alert']);
    });

    it('should merge partial email settings with defaults', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        email: { frequency: 'weekly-digest' },
      });

      expect(prefs.email.enabled).toBe(true); // default
      expect(prefs.email.frequency).toBe('weekly-digest'); // overridden
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES); // default
    });

    it('should merge partial SMS settings with defaults', () => {
      const prefs = service.createPreferences({
        userId: 'user-0001',
        sms: { enabled: true, phoneNumber: '+1555999888' },
      });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.phoneNumber).toBe('+1555999888');
      expect(prefs.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES); // default
    });

    it('should throw if user does not exist', () => {
      expect(() => service.createPreferences({ userId: 'nonexistent' })).toThrow(
        'User not found: nonexistent',
      );
    });

    it('should throw if preferences already exist', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(() => service.createPreferences({ userId: 'user-0001' })).toThrow(
        'Preferences already exist for user: user-0001',
      );
    });

    it('should generate sequential IDs', () => {
      const user2: User = {
        id: 'user-0002',
        name: 'Bob',
        email: 'bob@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      userRepo.save(user2);

      const prefs1 = service.createPreferences({ userId: 'user-0001' });
      const prefs2 = service.createPreferences({ userId: 'user-0002' });

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return preferences for a user', () => {
      service.createPreferences({ userId: 'user-0001' });

      const prefs = service.getPreferences('user-0001');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-0001');
    });

    it('should return undefined if no preferences exist', () => {
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });
  });

  describe('updatePreferences', () => {
    it('should update email enabled setting', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('immediate'); // unchanged
      expect(updated.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES); // unchanged
    });

    it('should update email frequency', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'daily-digest' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { subscribedCategories: ['system-alert'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['system-alert']);
    });

    it('should update SMS settings', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        sms: { enabled: true, phoneNumber: '+1555123456' },
      });

      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.phoneNumber).toBe('+1555123456');
      expect(updated.sms.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES); // unchanged
    });

    it('should update webhook settings', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        webhook: { enabled: true, url: 'https://hooks.example.com/notify' },
      });

      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.url).toBe('https://hooks.example.com/notify');
    });

    it('should update multiple channels at once', () => {
      service.createPreferences({ userId: 'user-0001' });

      const updated = service.updatePreferences('user-0001', {
        email: { frequency: 'daily-digest' },
        sms: { enabled: true, phoneNumber: '+1555123456' },
        webhook: { enabled: true, url: 'https://hooks.example.com/notify' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.sms.enabled).toBe(true);
      expect(updated.sms.phoneNumber).toBe('+1555123456');
      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.url).toBe('https://hooks.example.com/notify');
    });

    it('should throw if preferences do not exist', () => {
      expect(() =>
        service.updatePreferences('user-0001', { email: { enabled: false } }),
      ).toThrow('Preferences not found for user: user-0001');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(service.deletePreferences('user-0001')).toBe(true);
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return false if no preferences exist', () => {
      expect(service.deletePreferences('user-0001')).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true if no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-0001', 'order-confirmation')).toBe(true);
    });

    it('should return true if email is enabled and category is subscribed', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(service.shouldSendEmail('user-0001', 'order-confirmation')).toBe(true);
    });

    it('should return false if email is disabled', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      expect(service.shouldSendEmail('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return false if category is not subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['system-alert'] },
      });

      expect(service.shouldSendEmail('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return true for subscribed category even with limited subscriptions', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['system-alert', 'order-confirmation'] },
      });

      expect(service.shouldSendEmail('user-0001', 'order-confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'system-alert')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'order-status-update')).toBe(false);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false if no preferences exist (opt-in only)', () => {
      expect(service.shouldSendSms('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return false if SMS is disabled (default)', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(service.shouldSendSms('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return false if SMS is enabled but no phone number', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: { enabled: true },
      });

      expect(service.shouldSendSms('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return true if SMS is enabled with phone number and category is subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: { enabled: true, phoneNumber: '+1555123456' },
      });

      expect(service.shouldSendSms('user-0001', 'order-confirmation')).toBe(true);
    });

    it('should return false if category is not subscribed for SMS', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: {
          enabled: true,
          phoneNumber: '+1555123456',
          subscribedCategories: ['system-alert'],
        },
      });

      expect(service.shouldSendSms('user-0001', 'order-confirmation')).toBe(false);
      expect(service.shouldSendSms('user-0001', 'system-alert')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false if no preferences exist (opt-in only)', () => {
      expect(service.shouldSendWebhook('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return false if webhook is disabled (default)', () => {
      service.createPreferences({ userId: 'user-0001' });

      expect(service.shouldSendWebhook('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return false if webhook is enabled but no URL', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: { enabled: true },
      });

      expect(service.shouldSendWebhook('user-0001', 'order-confirmation')).toBe(false);
    });

    it('should return true if webhook is enabled with URL and category is subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: { enabled: true, url: 'https://hooks.example.com/notify' },
      });

      expect(service.shouldSendWebhook('user-0001', 'order-confirmation')).toBe(true);
    });

    it('should return false if category is not subscribed for webhook', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: {
          enabled: true,
          url: 'https://hooks.example.com/notify',
          subscribedCategories: ['system-alert'],
        },
      });

      expect(service.shouldSendWebhook('user-0001', 'order-confirmation')).toBe(false);
      expect(service.shouldSendWebhook('user-0001', 'system-alert')).toBe(true);
    });
  });

  describe('getSmsPhoneNumber', () => {
    it('should return undefined if no preferences exist', () => {
      expect(service.getSmsPhoneNumber('user-0001')).toBeUndefined();
    });

    it('should return undefined if no phone number configured', () => {
      service.createPreferences({ userId: 'user-0001' });
      expect(service.getSmsPhoneNumber('user-0001')).toBeUndefined();
    });

    it('should return phone number when configured', () => {
      service.createPreferences({
        userId: 'user-0001',
        sms: { phoneNumber: '+1555123456' },
      });
      expect(service.getSmsPhoneNumber('user-0001')).toBe('+1555123456');
    });
  });

  describe('getWebhookUrl', () => {
    it('should return undefined if no preferences exist', () => {
      expect(service.getWebhookUrl('user-0001')).toBeUndefined();
    });

    it('should return undefined if no URL configured', () => {
      service.createPreferences({ userId: 'user-0001' });
      expect(service.getWebhookUrl('user-0001')).toBeUndefined();
    });

    it('should return URL when configured', () => {
      service.createPreferences({
        userId: 'user-0001',
        webhook: { url: 'https://hooks.example.com/notify' },
      });
      expect(service.getWebhookUrl('user-0001')).toBe('https://hooks.example.com/notify');
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      statusChangeCallbacks.clear();
      notificationService = new NotificationService(eventBus);
      notificationService.setPreferencesService(service);
      resetNotificationIdCounter();
    });

    it('should send email notification when user has no preferences (default)', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Only email (default), no SMS or webhook without preferences
      expect(notificationService.getNotificationCount()).toBe(1);
      const notifications = notificationService.getNotifications();
      expect(notifications[0]?.channel).toBe('email');
    });

    it('should skip email notification when user has email disabled', async () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should skip notification when category is unsubscribed', async () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['system-alert'] },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send to multiple channels when all are opted in', async () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true },
        sms: { enabled: true, phoneNumber: '+1555123456' },
        webhook: { enabled: true, url: 'https://hooks.example.com/notify' },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notificationService.getNotificationCount()).toBe(3);
      const notifications = notificationService.getNotifications();
      const channels = notifications.map((n) => n.channel);
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).toContain('webhook');
    });

    it('should send email + SMS but not webhook when webhook is not configured', async () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: true },
        sms: { enabled: true, phoneNumber: '+1555123456' },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(notificationService.getNotificationCount()).toBe(2);
      const channels = notificationService.getNotifications().map((n) => n.channel);
      expect(channels).toContain('email');
      expect(channels).toContain('sms');
      expect(channels).not.toContain('webhook');
    });

    it('should skip status change notification when user opted out of email', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['order-confirmation'] },
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send status change notification when user is subscribed', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['order-status-update'] },
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should send status change to SMS when opted in', () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { enabled: false },
        sms: { enabled: true, phoneNumber: '+1555123456', subscribedCategories: ['order-status-update'] },
      });

      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      // Email disabled, SMS enabled for this category
      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('sms');
    });

    it('should respect per-channel category subscriptions independently', async () => {
      service.createPreferences({
        userId: 'user-0001',
        email: { subscribedCategories: ['order-confirmation'] },
        sms: {
          enabled: true,
          phoneNumber: '+1555123456',
          subscribedCategories: ['order-status-update'],
        },
      });

      // order-confirmation: email yes, sms no
      const orderEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(orderEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('email');

      notificationService.clearNotifications();
      resetNotificationIdCounter();

      // order-status-update: email no, sms yes
      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-0001',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(statusEvent);

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(notificationService.getNotifications()[0]?.channel).toBe('sms');
    });
  });
});

